import{_ as a,a as t}from"./chunks/webdav在win显示效果.BVTuSvY9.js";import{_ as i,o as l,c as s,a2 as d}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"د WebDAV Site Access (Beta)","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Safety/webdav-site-access.md","filePath":"ps/Safety/webdav-site-access.md","lastUpdated":1781962217000}'),n={name:"ps/Safety/webdav-site-access.md"};function o(r,e,c,p,h,b){return l(),s("div",null,[...e[0]||(e[0]=[d('<h1 id="د-webdav-site-access-beta" tabindex="-1">د WebDAV Site Access (Beta) <a class="header-anchor" href="#د-webdav-site-access-beta" aria-label="Permalink to &quot;د WebDAV Site Access (Beta)&quot;">​</a></h1><p>په Security Settings کې WebDAV setting ستاسو ImgBed site د WebDAV endpoint په توګه وړاندې کوي.</p><p>له فعالېدو وروسته، Windows، macOS، mobile file managers یا هر WebDAV-compatible client کارولای شئ، څو د ImgBed files لکه remote folder browse، upload، delete او manage کړئ.</p><p>دا د site WebDAV access entry دی. دا له Upload Settings کې WebDAV storage channel سره توپیر لري. upload channel files په third-party WebDAV service کې ساتي. دا setting ستاسو ImgBed site ته اجازه ورکوي چې clients ته WebDAV access ورکړي.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>admin panel پرانیزئ، بیا دې ځای ته لاړ شئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; WebDAV</span></span></code></pre></div><p>شته settings:</p><ul><li>Enable</li><li>Username</li><li>Password</li><li>Image loading mode</li><li>Default channel</li></ul><h2 id="دا-feature-څه-کوي" tabindex="-1">دا Feature څه کوي <a class="header-anchor" href="#دا-feature-څه-کوي" aria-label="Permalink to &quot;دا Feature څه کوي&quot;">​</a></h2><p>کله چې WebDAV فعال شي، ImgBed یو ثابت access URL ورکوي:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/dav</span></span></code></pre></div><p>دا URL د خپل ImgBed file directory سره د connect لپاره وکاروئ.</p><p>ښه use cases:</p><ul><li>د خپل computer file manager څخه ImgBed files مستقیم browse کړئ.</li><li>images د WebDAV folder ته drag کړئ او upload یې کړئ.</li><li>د local file manager څخه ImgBed folders organize کړئ.</li><li>WebDAV-compatible software د images sync یا manage لپاره وکاروئ.</li><li>admin panel له پرانیستلو پرته ImgBed content ته access وکړئ.</li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><h3 id="enable" tabindex="-1">Enable <a class="header-anchor" href="#enable" aria-label="Permalink to &quot;Enable&quot;">​</a></h3><p>WebDAV endpoint فعالوي.</p><p>کله چې disabled وي، clients د WebDAV له لارې connect نه شي کېدای.</p><h3 id="username-او-password" tabindex="-1">Username او Password <a class="header-anchor" href="#username-او-password" aria-label="Permalink to &quot;Username او Password&quot;">​</a></h3><p>دا credentials د connect پر وخت WebDAV clients کاروي.</p><p>جلا WebDAV username او password وکاروئ. admin password یا upload password مه reuse کوئ.</p><p>که username یا password تش وي، WebDAV clients سم connect نه شي کېدای.</p><h3 id="image-loading-mode" tabindex="-1">Image Loading Mode <a class="header-anchor" href="#image-loading-mode" aria-label="Permalink to &quot;Image Loading Mode&quot;">​</a></h3><p>Image loading mode ټاکي چې WebDAV clients د images د لوستلو پر وخت کوم image URL ته ترجیح ورکړي.</p><p>عام options:</p><table tabindex="0"><thead><tr><th>Mode</th><th>تشریح</th></tr></thead><tbody><tr><td>Smart loading</td><td>ImgBed د context له مخې انتخاب کوي. د عادي کارونې لپاره سپارښتنه کېږي.</td></tr><tr><td>Original</td><td>original images ته ترجیح ورکوي.</td></tr><tr><td>Thumbnail</td><td>thumbnails ته ترجیح ورکوي. د چټک preview لپاره ګټور دی.</td></tr></tbody></table><p>که ډاډه نه یاست، <code>Smart loading</code> وساتئ.</p><h3 id="default-channel" tabindex="-1">Default Channel <a class="header-anchor" href="#default-channel" aria-label="Permalink to &quot;Default Channel&quot;">​</a></h3><p>Default channel د WebDAV uploads لپاره کارېږي.</p><p>کله چې له Windows یا بل client څخه files د WebDAV directory ته copy کوئ، ImgBed یې د ټاکل شوي default upload channel له لارې upload کوي.</p><p>که default channel ټاکل شوی نه وي، browsing ښايي کار وکړي، خو uploads ناکامېدای شي.</p><h2 id="په-windows-11-کې-webdav-ته-access" tabindex="-1">په Windows 11 کې WebDAV ته Access <a class="header-anchor" href="#په-windows-11-کې-webdav-ته-access" aria-label="Permalink to &quot;په Windows 11 کې WebDAV ته Access&quot;">​</a></h2><p>Windows 11 کولای شي WebDAV د network location په توګه اضافه کړي.</p><ol><li><code>This PC</code> پرانیزئ.</li><li><code>Add a network location</code> وټاکئ.</li><li><code>https://your-domain.com/dav</code> ولیکئ.</li><li>د غوښتنې پر وخت خپل WebDAV username او password ولیکئ.</li><li>wizard بشپړ کړئ. وروسته WebDAV directory په File Explorer کې پرانیستل کېدای شي.</li></ol><p><img src="'+a+'" alt="Add WebDAV in Windows 11" loading="lazy"></p><p>له اضافه کېدو وروسته، WebDAV directory په Windows File Explorer کې ښکاري. د عادي folder په څېر files پرانیستل، copy او manage کولای شئ.</p><p><img src="'+t+'" alt="WebDAV in Windows" loading="lazy"></p><h2 id="supported-operations" tabindex="-1">Supported Operations <a class="header-anchor" href="#supported-operations" aria-label="Permalink to &quot;Supported Operations&quot;">​</a></h2><p>له بریالي WebDAV connection وروسته، عموما دا کارونه کولای شئ:</p><ul><li>files او folders وګورئ.</li><li>files upload کړئ.</li><li>folders جوړ کړئ.</li><li>files یا folders rename کړئ.</li><li>files move کړئ.</li><li>files delete کړئ.</li></ul><p>WebDAV د ورځني access او کوچني file management لپاره مناسب دی. د لویو moves، bulk deletes یا پېچلي organization لپاره admin panel وکاروئ.</p><h2 id="login-device-management" tabindex="-1">Login Device Management <a class="header-anchor" href="#login-device-management" aria-label="Permalink to &quot;Login Device Management&quot;">​</a></h2><p>بریالي WebDAV connections د Login Device Management په WebDAV tab کې هم ښکاري.</p><p>هلته WebDAV clients کتلای شئ او د اړتیا پر وخت زاړه devices force offline کولای شئ.</p><p>که WebDAV username یا password بدل کړئ، زاړه clients باید بیا sign in وکړي.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="windows-بیا-بیا-username-او-password-غواړي" tabindex="-1">Windows بیا بیا Username او Password غواړي <a class="header-anchor" href="#windows-بیا-بیا-username-او-password-غواړي" aria-label="Permalink to &quot;Windows بیا بیا Username او Password غواړي&quot;">​</a></h3><p>وګورئ:</p><ul><li>URL دا دی: <code>https://your-domain.com/dav</code>.</li><li>username او password له WebDAV settings سره برابر دي.</li><li>WebDAV فعال دی.</li><li>site د HTTPS له لارې access کېدای شي.</li></ul><h3 id="browsing-کار-کوي،-خو-upload-ناکامېږي" tabindex="-1">Browsing کار کوي، خو Upload ناکامېږي <a class="header-anchor" href="#browsing-کار-کوي،-خو-upload-ناکامېږي" aria-label="Permalink to &quot;Browsing کار کوي، خو Upload ناکامېږي&quot;">​</a></h3><p><code>Default channel</code> وګورئ.</p><p>WebDAV uploads default upload channel غواړي. که missing، disabled یا misconfigured وي، uploads ناکامېدای شي.</p><h3 id="access-speed-بې-ثباته-دی" tabindex="-1">Access Speed بې ثباته دی <a class="header-anchor" href="#access-speed-بې-ثباته-دی" aria-label="Permalink to &quot;Access Speed بې ثباته دی&quot;">​</a></h3><p>د WebDAV performance پر client، network، file count او default upload channel پورې تړلی دی.</p><p>که directory ډېر files ولري، files په folders کې organize کړئ او ټول په یوه directory کې مه ساتئ.</p><h2 id="security-recommendations" tabindex="-1">Security Recommendations <a class="header-anchor" href="#security-recommendations" aria-label="Permalink to &quot;Security Recommendations&quot;">​</a></h2><ul><li>د WebDAV access لپاره HTTPS وکاروئ.</li><li>strong password وټاکئ.</li><li>WebDAV password له نابلدو خلکو سره مه شریکوئ.</li><li>چې WebDAV نه کاروئ، بند یې کړئ.</li><li>په Login Device Management کې unused WebDAV devices وخت په وخت پاک کړئ.</li></ul><h2 id="د-webdav-upload-file-size" tabindex="-1">د WebDAV Upload File Size <a class="header-anchor" href="#د-webdav-upload-file-size" aria-label="Permalink to &quot;د WebDAV Upload File Size&quot;">​</a></h2><p>WebDAV clients د browser upload page د large-file chunking flow نه کاروي. د لاندې سپارښتل شوو limits څخه لوړو files لپاره web upload page وکاروئ.</p><table tabindex="0"><thead><tr><th>Default Upload Channel</th><th style="text-align:right;">Suggested Single-File Limit for WebDAV</th></tr></thead><tbody><tr><td>Telegram</td><td style="text-align:right;">20 MB</td></tr><tr><td>Discord</td><td style="text-align:right;">10 MB</td></tr><tr><td>Cloudflare R2</td><td style="text-align:right;">30 MB</td></tr><tr><td>S3</td><td style="text-align:right;">30 MB</td></tr><tr><td>GitHub Releases</td><td style="text-align:right;">64 MB</td></tr><tr><td>GitLab Packages</td><td style="text-align:right;">64 MB</td></tr><tr><td>Hugging Face</td><td style="text-align:right;">20 MB</td></tr><tr><td>OneDrive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Google Drive</td><td style="text-align:right;">30 MB</td></tr><tr><td>Dropbox</td><td style="text-align:right;">30 MB</td></tr><tr><td>Yandex Disk</td><td style="text-align:right;">30 MB</td></tr><tr><td>pCloud</td><td style="text-align:right;">30 MB</td></tr><tr><td>WebDAV</td><td style="text-align:right;">64 MB</td></tr></tbody></table>',61)])])}const f=i(n,[["render",o]]);export{m as __pageData,f as default};
